const items = $input.all().map(i => i.json);
if (items.length === 0) return [{ json: { has_items: false, digest: 'RECON OS SLA Watchdog: All clear — no SLA breaches.', overdue_critical: 0 } }];

const overdue = items.filter(i => parseFloat(i.days_overdue) > 0);
const warning = items.filter(i => parseFloat(i.days_overdue) <= 0);
const overdueCritical = overdue.filter(i => ['immediate_attention','high_priority'].includes(i.priority_bucket));

const formatItem = i => {
  const daysOverdue = Math.round(parseFloat(i.days_overdue||0));
  const tag = daysOverdue > 0 ? `🔴 ${daysOverdue}d OVERDUE` : `⚠️ ${Math.round(Math.abs(parseFloat(i.days_overdue||0)))}d to SLA`;
  return `  ${tag} | [${i.severity?.toUpperCase()}] ${i.title}\n    Client: ${i.client_name} | Asset: ${i.asset_value} | Owner: ${i.remediation_owner || 'Unassigned'}`;
};

const digest = [
  `🚨 RECON OS — SLA Watchdog — ${new Date().toISOString().split('T')[0]}`,
  `Total items at risk: ${items.length} (${overdue.length} overdue, ${warning.length} approaching)`,
  ``,
  overdue.length > 0 ? `OVERDUE (${overdue.length}):` : '',
  ...overdue.map(formatItem),
  ``,
  warning.length > 0 ? `APPROACHING SLA (${warning.length}):` : '',
  ...warning.slice(0,5).map(formatItem)
].filter(l => l !== null && l !== '').join('\n');

return [{ json: {
  has_items: items.length > 0,
  digest,
  overdue_count: overdue.length,
  warning_count: warning.length,
  overdue_critical: overdueCritical.length,
  items
} }];
